import{_ as i,c as t,o as s,aj as a}from"./chunks/framework.HLg5PcC2.js";const g=JSON.parse('{"title":"Authentication","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/authentication.md","filePath":"getting-started/authentication.md"}'),n={name:"getting-started/authentication.md"};function o(l,e,r,h,p,d){return s(),t("div",null,[...e[0]||(e[0]=[a(`<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to “Authentication”">​</a></h1><p>The template app comes with a complete authentication flow out of the box — login UI, token management, session handling, and multiple sign-in methods. You don&#39;t need to build any auth screens or wire up the client yourself.</p><p>The two things you may want to configure are:</p><ol><li><strong>Email sign-in method</strong> — Magic Link (default) or One-Time Password, controlled by a prop on the login component</li><li><strong>Google OAuth</strong> — Optional, requires setting up a Google OAuth client</li></ol><h2 id="choosing-your-email-sign-in-method" tabindex="-1">Choosing Your Email Sign-In Method <a class="header-anchor" href="#choosing-your-email-sign-in-method" aria-label="Permalink to “Choosing Your Email Sign-In Method”">​</a></h2><p>The <code>PrimitiveLogin</code> component supports two email-based sign-in methods:</p><table tabindex="0"><thead><tr><th>Method</th><th>Value</th><th>How It Works</th></tr></thead><tbody><tr><td><strong>Magic Link</strong> (default)</td><td><code>&quot;magic_link&quot;</code></td><td>User receives a clickable sign-in link via email</td></tr><tr><td><strong>One-Time Password</strong></td><td><code>&quot;one_time_code&quot;</code></td><td>User receives a 6-digit code to enter in the app</td></tr></tbody></table><p>Set this via the <code>emailAuthMethod</code> prop on the <code>PrimitiveLogin</code> component in your login page:</p><div class="language-vue"><button title="Copy Code" class="copy"></button><span class="lang">vue</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">PrimitiveLogin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  appName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;My App&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  defaultContinueRoute</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;home&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  emailAuthMethod</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;one_time_code&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/&gt;</span></span></code></pre></div><p>If you don&#39;t specify <code>emailAuthMethod</code>, it defaults to <code>&quot;magic_link&quot;</code>.</p><h2 id="setting-up-google-oauth-optional" tabindex="-1">Setting Up Google OAuth (Optional) <a class="header-anchor" href="#setting-up-google-oauth-optional" aria-label="Permalink to “Setting Up Google OAuth (Optional)”">​</a></h2><p>Google OAuth lets users sign in with their Google account. This requires a one-time setup in both the Google Cloud Console and your Primitive app.</p><h3 id="_1-create-a-google-oauth-client" tabindex="-1">1. Create a Google OAuth Client <a class="header-anchor" href="#_1-create-a-google-oauth-client" aria-label="Permalink to “1. Create a Google OAuth Client”">​</a></h3><p>Go to the <a href="https://console.cloud.google.com/auth/clients" target="_blank" rel="noreferrer">Google Cloud Console OAuth page</a> and create a Web application client:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th></tr></thead><tbody><tr><td>Authorized JavaScript origins</td><td><code>http://localhost:5173</code></td></tr><tr><td>Authorized redirect URIs</td><td><code>http://localhost:5173/oauth/callback</code></td></tr></tbody></table><p>Note your <strong>Client ID</strong> and <strong>Client Secret</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Production Setup</p><p>When deploying to production, add your production domain to these settings alongside localhost.</p></div><h3 id="_2-configure-in-primitive" tabindex="-1">2. Configure in Primitive <a class="header-anchor" href="#_2-configure-in-primitive" aria-label="Permalink to “2. Configure in Primitive”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> oauth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set-google</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --client-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR_CLIENT_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --client-secret</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> YOUR_CLIENT_SECRET</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apps</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:5173</span></span></code></pre></div><p>Or configure via the <a href="https://admin.primitiveapi.com/login" target="_blank" rel="noreferrer">Admin Console</a> under your app&#39;s Google OAuth settings.</p><p>That&#39;s it — the template&#39;s login component automatically shows a &quot;Sign in with Google&quot; button when Google OAuth is configured.</p><h2 id="passkeys-webauthn" tabindex="-1">Passkeys (WebAuthn) <a class="header-anchor" href="#passkeys-webauthn" aria-label="Permalink to “Passkeys (WebAuthn)”">​</a></h2><p>Passkeys let returning users sign in with biometrics (fingerprint, face) or hardware security keys. The template&#39;s login flow supports passkeys automatically — users can register a passkey after signing in, then use it for future logins.</p><h2 id="email-template-customization" tabindex="-1">Email Template Customization <a class="header-anchor" href="#email-template-customization" aria-label="Permalink to “Email Template Customization”">​</a></h2><p>Customize the emails sent for magic links and OTP codes:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># View available template variables</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> email-templates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> variables</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> magic-link</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Set a custom template</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> email-templates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> magic-link</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --subject</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Sign in to MyApp&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --html-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./magic-link.html</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --text-file</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./magic-link.txt</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Test the template</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> email-templates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> magic-link</span></span></code></pre></div><h2 id="invitations-and-pending-shares" tabindex="-1">Invitations and Pending Shares <a class="header-anchor" href="#invitations-and-pending-shares" aria-label="Permalink to “Invitations and Pending Shares”">​</a></h2><p>Any sign-in method resolves pending invitations and email-based shares automatically:</p><ul><li>If an invitation exists for the user&#39;s email, it&#39;s consumed and the user joins the app.</li><li>Any pending document shares, group adds, or collection adds addressed to their email are applied atomically after the account is created — documents are shared, group and collection memberships are granted.</li><li>Domain-mode apps re-validate the email domain at resolution time. A pending share for <code>alice@outside.com</code> won&#39;t land in an app restricted to <code>@mycompany.com</code>.</li></ul><p>From the end-user&#39;s perspective: they sign in for the first time, and the things other people invited them into are already there. No manual &quot;accept invitation&quot; step.</p><p>See <a href="./sharing-and-invitations.html">Sharing and Invitations</a> for how to create these shares.</p><h2 id="disabling-a-user-per-app" tabindex="-1">Disabling a User Per App <a class="header-anchor" href="#disabling-a-user-per-app" aria-label="Permalink to “Disabling a User Per App”">​</a></h2><p>Admins can disable a user&#39;s access to a single app from the admin console without deleting their global account. A disabled user&#39;s existing tokens are revoked, open WebSocket connections are dropped, and any subsequent sign-in attempt (passkey, OAuth, magic link, OTP) is rejected with the error code <code>AUTH_USER_DISABLED</code>. Re-enabling restores access immediately; no re-invitation is needed.</p><p>Display <code>AUTH_USER_DISABLED</code> in your sign-in UI as a distinct error so the user understands they should contact an admin rather than retrying or trying a different method.</p><h2 id="test-user-sign-in-for-automated-testing" tabindex="-1">Test User Sign-In for Automated Testing <a class="header-anchor" href="#test-user-sign-in-for-automated-testing" aria-label="Permalink to “Test User Sign-In for Automated Testing”">​</a></h2><p>For automated tests, Primitive supports a <code>+primitivetest</code> OTP bypass. Each app maintains a <code>testAccountBaseEmails</code> whitelist of base addresses (e.g. <code>alice@example.com</code>). For any whitelisted base, derived addresses of the form <code>&lt;base-local&gt;+primitivetest&lt;suffix&gt;@&lt;base-domain&gt;</code> skip the real email send on <code>otpRequest</code> and accept the magic code <code>000000</code> on <code>otpVerify</code>, returning a 30-minute token.</p><p>A single base authorizes unlimited role-distinguished derivatives — Gmail and Google Workspace deliver every <code>&lt;base&gt;+anything@&lt;domain&gt;</code> to the same inbox, so one real mailbox covers a fleet of test users:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>alice+primitivetest@example.com</span></span>
<span class="line"><span>alice+primitivetest-teacher@example.com</span></span>
<span class="line"><span>alice+primitivetest-student@example.com</span></span>
<span class="line"><span>alice+primitivetest.ci-001@example.com</span></span></code></pre></div><p>The suffix matches <code>[A-Za-z0-9._-]*</code> (possibly empty). Only single-<code>+</code> shapes are accepted: <code>alice+team+primitivetest-x@…</code> does not match.</p><p>Guardrails worth knowing:</p><ul><li><strong>Per-app whitelist.</strong> A derived address is honored only when its base appears on this app&#39;s <code>testAccountBaseEmails</code> list. Apps without a whitelist have no bypass at all.</li><li><strong>AppUser must already exist.</strong> The bypass never auto-provisions. The derived account has to be a member of the app — through normal invitation, signup, or a deferred grant — before <code>000000</code> will let it in. This keeps a public-mode app from being signed up as <code>attacker+primitivetest@&lt;whitelisted&gt;</code>.</li><li><strong>30-minute tokens.</strong> Access tokens issued via this path expire after 30 minutes regardless of your normal session length, and carry a <code>primitiveBypass: true</code> claim. The whitelist is re-checked on each request, so removing a base from the list revokes its derived sessions immediately.</li><li><strong>Reserved at admin/role/invitation boundaries.</strong> A <code>+primitivetest*</code> email may sign in as an ordinary <code>member</code> user but cannot hold admin or owner privileges, and cannot be the recipient of an admin/role invitation. Attempts return <code>RESERVED_EMAIL_FOR_ADMIN</code>.</li><li><strong>Whitelist limits.</strong> Up to 50 base emails per app. A base may not itself be a <code>+primitivetest</code> derivative.</li></ul><p>Use this for integration tests and local dev. Do not rely on it for staging or production flows.</p><p>See <a href="./primitive-cli.html#test-users-for-automated-testing">Primitive CLI</a> for managing the whitelist and signing in from a test.</p><h2 id="how-it-works-under-the-hood" tabindex="-1">How It Works Under the Hood <a class="header-anchor" href="#how-it-works-under-the-hood" aria-label="Permalink to “How It Works Under the Hood”">​</a></h2><p>For reference, here&#39;s what the template handles for you:</p><ul><li><strong>Token management</strong> — Access tokens are short-lived and refreshed automatically in the background. Refresh tokens are stored securely.</li><li><strong>Auth state</strong> — The client emits <code>authStateChanged</code> events that the template&#39;s router uses to redirect between login and app pages.</li><li><strong>Logout</strong> — Calling <code>client.auth.logout()</code> clears tokens, closes documents, and fires the auth state event. The template&#39;s UI includes a logout button.</li><li><strong>Safari compatibility</strong> — The template&#39;s production deployment includes a first-party refresh proxy for Safari&#39;s strict cookie policies.</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./users-and-groups.html">Users and Groups</a></strong> — Organize users and manage access control</li><li><strong><a href="./sharing-and-invitations.html">Sharing and Invitations</a></strong> — Invitations, email-based shares, access requests</li><li><strong><a href="/primitive-docs/">Overview</a></strong> — See how auth fits into the platform</li></ul>`,48)])])}const k=i(n,[["render",o]]);export{g as __pageData,k as default};
